import{_ as d,o as a,c as r,a2 as e}from"./chunks/framework.Bjylvv1V.js";const g=JSON.parse('{"title":"시작하기","description":"","frontmatter":{},"headers":[],"relativePath":"guide/getting-started.md","filePath":"guide/getting-started.md","lastUpdated":1772074398000}'),i={name:"guide/getting-started.md"};function o(h,t,l,n,s,c){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="시작하기" tabindex="-1">시작하기 <a class="header-anchor" href="#시작하기" aria-label="Permalink to &quot;시작하기&quot;">​</a></h1><p>XpERP는 아파트 관리사무소의 전반적인 업무를 지원하는 통합 ERP 시스템입니다.</p><h2 id="xperp-접속-방법" tabindex="-1">XpERP 접속 방법 <a class="header-anchor" href="#xperp-접속-방법" aria-label="Permalink to &quot;XpERP 접속 방법&quot;">​</a></h2><ol><li>웹 브라우저에서 XpERP 사이트에 접속합니다</li><li>발급받은 아이디와 비밀번호로 로그인합니다</li><li>메인 화면에서 필요한 메뉴를 선택합니다</li></ol><h2 id="시스템-구성" tabindex="-1">시스템 구성 <a class="header-anchor" href="#시스템-구성" aria-label="Permalink to &quot;시스템 구성&quot;">​</a></h2><p>XpERP는 다음 14개 대메뉴로 구성되어 있습니다:</p><table tabindex="0"><thead><tr><th>번호</th><th>메뉴</th><th>설명</th></tr></thead><tbody><tr><td>1</td><td><a href="/appr/">Xp전자결재</a></td><td>전자결재 문서 작성 및 승인</td></tr><tr><td>2</td><td><a href="/docs-menu/">Xp문서함</a></td><td>문서 보관 및 관리</td></tr><tr><td>3</td><td><a href="/dang/">단지관리</a></td><td>단지정보, 환경설정, 조견표</td></tr><tr><td>4</td><td><a href="/occp/">입주자</a></td><td>입주/전출, 차량, 개인정보 관리</td></tr><tr><td>5</td><td><a href="/insp/">검침</a></td><td>전기, 수도, 가스 등 계량기 검침</td></tr><tr><td>6</td><td><a href="/impo/">부과</a></td><td>관리비 부과 처리</td></tr><tr><td>7</td><td><a href="/recp/">수납</a></td><td>관리비 수납 및 미납 관리</td></tr><tr><td>8</td><td><a href="/acct/">회계</a></td><td>전표, 장부, 결산, 예산 관리</td></tr><tr><td>9</td><td><a href="/pay/">인사/급여</a></td><td>직원 인사 및 급여 관리</td></tr><tr><td>10</td><td><a href="/afms/">장기수선계획</a></td><td>장기수선충당금 관리</td></tr><tr><td>11</td><td><a href="/premium/">프리미엄</a></td><td>프리미엄 서비스</td></tr><tr><td>12</td><td><a href="/jobm/">민원</a></td><td>입주민 민원 접수 및 처리</td></tr><tr><td>13</td><td><a href="/bank/">아파트뱅크</a></td><td>은행 거래 및 이체 관리</td></tr><tr><td>14</td><td><a href="/apti/">아파트아이</a></td><td>입주민 모바일 앱 서비스</td></tr></tbody></table><h2 id="권장-학습-순서" tabindex="-1">권장 학습 순서 <a class="header-anchor" href="#권장-학습-순서" aria-label="Permalink to &quot;권장 학습 순서&quot;">​</a></h2><p>신규 사용자라면 다음 순서로 학습하는 것을 권장합니다:</p><ol><li><strong><a href="/guide/glossary.html">용어 사전</a></strong> - 기본 용어 이해</li><li><strong><a href="/guide/workflow.html">월간 업무 흐름</a></strong> - 전체 업무 흐름 파악</li><li><strong><a href="/dang/">단지관리</a></strong> - 기본 설정 확인</li><li><strong><a href="/occp/">입주자</a></strong> - 세대 정보 관리</li><li><strong><a href="/insp/">검침</a> → <a href="/impo/">부과</a> → <a href="/recp/">수납</a></strong> - 핵심 월간 업무</li><li><strong><a href="/acct/">회계</a></strong> - 회계 처리</li></ol><h2 id="업무-시나리오-가이드" tabindex="-1">업무 시나리오 가이드 <a class="header-anchor" href="#업무-시나리오-가이드" aria-label="Permalink to &quot;업무 시나리오 가이드&quot;">​</a></h2><p>실제 업무를 처리할 때는 **<a href="/guide/scenarios/">업무 시나리오 가이드</a>**를 활용하세요. 메뉴 설명이 아니라 &quot;<strong>이 업무를 어떻게 처리하는가</strong>&quot;에 초점을 맞추어 단계별로 따라 할 수 있습니다.</p><table tabindex="0"><thead><tr><th>업무</th><th>시나리오 가이드</th><th>소요 시간</th></tr></thead><tbody><tr><td>계량기 검침</td><td><a href="/guide/scenarios/meter-reading.html">검침 처리</a></td><td>1~2시간</td></tr><tr><td>관리비 산정·부과</td><td><a href="/guide/scenarios/billing.html">관리비 부과</a></td><td>30분</td></tr><tr><td>관리비 수납</td><td><a href="/guide/scenarios/collection.html">수납 처리</a></td><td>20분</td></tr><tr><td>체납 관리</td><td><a href="/guide/scenarios/overdue.html">미수금 관리</a></td><td>15분</td></tr><tr><td>월 마감</td><td><a href="/guide/scenarios/month-closing.html">월말 마감</a></td><td>40분</td></tr><tr><td>지출 기록</td><td><a href="/guide/scenarios/expense-voucher.html">지출 전표 입력</a></td><td>건당 5분</td></tr><tr><td>잔액 대사</td><td><a href="/guide/scenarios/bank-reconciliation.html">통장 대사</a></td><td>20분</td></tr><tr><td>입주·퇴거</td><td><a href="/guide/scenarios/move-in-out.html">전출입 처리</a></td><td>건당 15분</td></tr><tr><td>급여 지급</td><td><a href="/guide/scenarios/payroll.html">급여 처리</a></td><td>30분</td></tr><tr><td>결산</td><td><a href="/guide/scenarios/year-end.html">연말 결산</a></td><td>2시간</td></tr></tbody></table><h2 id="도움이-필요할-때" tabindex="-1">도움이 필요할 때 <a class="header-anchor" href="#도움이-필요할-때" aria-label="Permalink to &quot;도움이 필요할 때&quot;">​</a></h2><ul><li>업무별 단계 가이드는 <a href="/guide/scenarios/">업무 시나리오</a>를 참고하세요</li><li>각 메뉴 페이지에서 상세한 사용법을 확인하세요</li><li>용어가 낯설다면 <a href="/guide/glossary.html">용어 사전</a>을 참고하세요</li></ul>',15)])])}const p=d(i,[["render",o]]);export{g as __pageData,p as default};
